    board[input[0]-'a'][(input[1]-'0')-1]=1;
    board[input1[0]-'a'][(input1[1]-'0')-1]=1;
    int rook=input[0]-'a';  int rook1=(input[1]-'0')-1;
    for(i=0;i<8;i++){
            for(a=0;a<8;a++){
            if(board[i][a] != 1 && board[i+2][a+1] != 1 && board[i+2][a-1] != 1 && board[i-2][a+1] != 1 && board[i-2][a-1] != 1 && board[i-1][a+2] != 1 && board[i+1][a+2] != 1 && board[i-1][a-2] != 1 && board[i+1][a-2] != 1 && i!=rook && a!=rook1){
