#![allow(unused_imports)]
use std::collections;
use std::io;

struct Input {
    buffer: collections::VecDeque<String>,
}

impl Input {
    fn new() -> Input {
        Input {
            buffer: collections::VecDeque::new(),
        }
    }

    fn next<T: std::str::FromStr>(&mut self) -> T {
        while self.buffer.len() == 0 {
            let mut line = String::new();
            std::io::stdin().read_line(&mut line).ok();
            for word in line.split_whitespace() {
                self.buffer.push_back(word.to_string())
            }
        }

        let front = self.buffer.pop_front().unwrap();
        front.parse::<T>().ok().unwrap()
    }
}

fn main() {
    let mut input = Input::new();
    let rook_str: String = input.next();
    let knight_str: String = input.next();

    let rook_pos = (
        rook_str.chars().nth(0).unwrap() as i32 - 'a' as i32,
        rook_str.chars().nth(1).unwrap() as i32 - '1' as i32,
    );

    let knight_pos = (
        knight_str.chars().nth(0).unwrap() as i32 - 'a' as i32,
        knight_str.chars().nth(1).unwrap() as i32 - '1' as i32,
    );

    let mut count = 8 * 8;

    for j in 0..8 {
        for k in 0..8 {
            if rook_pos.0 == j || rook_pos.1 == k {
                count -= 1;
            } else if knight_pos.0 == j && knight_pos.1 == k {
                count -= 1;
            } else if (rook_pos.0 - j).abs() == 2 && (rook_pos.1 - k).abs() == 1 {
                count -= 1;
            } else if (rook_pos.0 - j).abs() == 1 && (rook_pos.1 - k).abs() == 2 {
                count -= 1;
            } else if (knight_pos.0 - j).abs() == 2 && (knight_pos.1 - k).abs() == 1 {
                count -= 1;
            } else if (knight_pos.0 - j).abs() == 1 && (knight_pos.1 - k).abs() == 2 {
                count -= 1;
            }
        }
    }

    println!("{:?}", count);
}
